        if patterns is None:
            return bool(self._generic_international_pattern.match(normalized))

        national_pattern, international_pattern = patterns
        return bool(national_pattern.match(normalized)) or bool(international_pattern.match(normalized))

    @staticmethod
    def _normalize(phone: str) -> str:
        phone = phone.strip()
        has_plus = phone.startswith('+')
        digits = re.sub(r'\D', '', phone)
        return f'+{digits}' if has_plus else digits

